const body = $input.first().json.body || $input.first().json;

// ── Required field checks ────────────────────────────────────
if (!body.recipientEmail) {
  throw new Error('recipientEmail is required.');
}
if (!body.fileUrl && !body.filename) {
  throw new Error('Provide either fileUrl (remote file) or filename (binary upload).');
}

// ── Email format validation ───────────────────────────────────
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.recipientEmail)) {
  throw new Error(`Invalid recipientEmail: ${body.recipientEmail}`);
}

// ── Expiry hours — clamp between 1 and 168 (1 week) ──────────
const requestedHours = parseFloat(body.expiryHours);
const expiryHours = isNaN(requestedHours)
  ? parseFloat($vars.DEFAULT_EXPIRY_HOURS || '24')
  : Math.min(168, Math.max(1, requestedHours));

// ── Filename & extension ──────────────────────────────────────
const filename = body.filename ||
  body.fileUrl?.split('?')[0].split('/').pop() ||
  'preview.pdf';
const ext = filename.split('.').pop()?.toLowerCase() || 'pdf';
const allowedExts = ['pdf', 'jpg', 'jpeg', 'png', 'docx', 'pptx', 'mp4', 'zip'];
if (!allowedExts.includes(ext)) {
  throw new Error(`File type .${ext} not supported. Accepted: ${allowedExts.join(', ')}`);
}

// ── Sanitise strings ──────────────────────────────────────────
const s = v => String(v || '').trim().slice(0, 255);

return [{
  json: {
    fileUrl: body.fileUrl || null,
    filename,
    ext,
    recipientEmail: body.recipientEmail.toLowerCase().trim(),
    recipientName: s(body.recipientName) || 'Valued Client',
    projectName: s(body.projectName) || 'Project Preview',
    senderName: s(body.senderName) || s($vars.AGENCY_NAME) || 'The Team',
    agencyEmail: s(body.agencyEmail) || s($vars.AGENCY_EMAIL),
    expiryHours,
    message: s(body.message),
    receivedAt: new Date().toISOString()
  }
}];

const uploadResp = $input.first().json;
const meta = $('Validate Payload').first().json;

const cdnUrl =
  uploadResp.url ||
  uploadResp.link ||
  uploadResp.data?.url ||
  uploadResp.file?.url ||
  uploadResp.shortUrl;

if (!cdnUrl) {
  throw new Error('Upload to URL returned no public URL. Raw: ' + JSON.stringify(uploadResp).slice(0, 300));
}

return [{
  json: {
    ...meta,
    cdnUrl: cdnUrl.replace(/^http:\/\//, 'https://'),
    uploadId: uploadResp.id || uploadResp.data?.id || null,
    fileSizeBytes: uploadResp.size || uploadResp.data?.size || null
  }
}];

const data = $input.first().json;

// ── Generate unique token ─────────────────────────────────────
// Hex token built from timestamp + random component
const randomPart = Math.random().toString(16).slice(2, 10).toUpperCase();
const timePart = Date.now().toString(16).toUpperCase();
const token = `${timePart}-${randomPart}`;

// ── Compute expiry timestamp ──────────────────────────────────
const sentAt = new Date();
const expiresAt = new Date(sentAt.getTime() + data.expiryHours * 60 * 60 * 1000);

// ── Human-readable expiry string for emails ───────────────────
const formatDate = d => d.toUTCString().replace('GMT', 'UTC');

// ── Compute wait duration in milliseconds for Wait node ───────
const waitMs = data.expiryHours * 60 * 60 * 1000;

// ── Build branded preview email HTML ─────────────────────────
const previewEmailHtml = `
<!DOCTYPE html>
<html>
<body style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; max-width: 600px; margin: 0 auto; padding: 32px; color: #1a1a1a;">
  <div style="border-bottom: 3px solid #4F46E5; padding-bottom: 16px; margin-bottom: 24px;">
    <h1 style="margin: 0; font-size: 22px; color: #4F46E5;">${data.senderName}</h1>
    <p style="margin: 4px 0 0; color: #6b7280; font-size: 14px;">Secure File Preview</p>
  </div>
  <p style="font-size: 16px;">Hi ${data.recipientName},</p>
  <p>You have a new file available for preview:</p>
  <div style="background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 8px; padding: 20px; margin: 20px 0;">
    <p style="margin: 0 0 8px; font-weight: 600; font-size: 18px;">📄 ${data.filename}</p>
    <p style="margin: 0; color: #6b7280; font-size: 14px;">Project: ${data.projectName}</p>
  </div>
  ${data.message ? `<p style="background: #eff6ff; border-left: 4px solid #4F46E5; padding: 12px 16px; border-radius: 0 6px 6px 0; font-style: italic;">${data.message}</p>` : ''}
  <div style="text-align: center; margin: 32px 0;">
    <a href="${data.cdnUrl}" style="background: #4F46E5; color: white; padding: 14px 32px; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 16px; display: inline-block;">View File</a>
  </div>
  <div style="background: #fef3c7; border: 1px solid #fbbf24; border-radius: 6px; padding: 12px 16px; font-size: 13px; color: #92400e;">
    ⏱️ <strong>This link expires on ${formatDate(expiresAt)}</strong> (${data.expiryHours} hours from now). After that, you will no longer be able to access this file.
  </div>
  <p style="font-size: 13px; color: #9ca3af; margin-top: 32px;">Sent securely via ${data.senderName} · Token: ${token}</p>
</body>
</html>`;

// ── Build expiry notification HTML (to client) ────────────────
const expiryClientHtml = `
<!DOCTYPE html>
<html>
<body style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; max-width: 600px; margin: 0 auto; padding: 32px; color: #1a1a1a;">
  <div style="border-bottom: 3px solid #ef4444; padding-bottom: 16px; margin-bottom: 24px;">
    <h1 style="margin: 0; font-size: 22px; color: #ef4444;">Preview Link Expired</h1>
  </div>
  <p>Hi ${data.recipientName},</p>
  <p>The preview link for <strong>${data.filename}</strong> (Project: ${data.projectName}) has now expired and is no longer accessible.</p>
  <p>If you need continued access to this file, please contact <strong>${data.senderName}</strong>.</p>
  <p style="font-size: 13px; color: #9ca3af;">Token: ${token} · Expired: ${formatDate(expiresAt)}</p>
</body>
</html>`;

// ── Build agency summary HTML ─────────────────────────────────
const agencySummaryHtml = `
<!DOCTYPE html>
<html>
<body style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; max-width: 600px; margin: 0 auto; padding: 32px; color: #1a1a1a;">
  <h2>🔒 Link Lifecycle Complete</h2>
  <table style="width: 100%; border-collapse: collapse; font-size: 14px;">
    <tr style="border-bottom: 1px solid #e5e7eb;"><td style="padding: 8px; color: #6b7280;">Token</td><td style="padding: 8px; font-weight: 600;">${token}</td></tr>
    <tr style="border-bottom: 1px solid #e5e7eb;"><td style="padding: 8px; color: #6b7280;">File</td><td style="padding: 8px;">${data.filename}</td></tr>
    <tr style="border-bottom: 1px solid #e5e7eb;"><td style="padding: 8px; color: #6b7280;">Project</td><td style="padding: 8px;">${data.projectName}</td></tr>
    <tr style="border-bottom: 1px solid #e5e7eb;"><td style="padding: 8px; color: #6b7280;">Recipient</td><td style="padding: 8px;">${data.recipientName} &lt;${data.recipientEmail}&gt;</td></tr>
    <tr style="border-bottom: 1px solid #e5e7eb;"><td style="padding: 8px; color: #6b7280;">Sent At</td><td style="padding: 8px;">${formatDate(sentAt)}</td></tr>
    <tr style="border-bottom: 1px solid #e5e7eb;"><td style="padding: 8px; color: #6b7280;">Expired At</td><td style="padding: 8px;">${formatDate(expiresAt)}</td></tr>
    <tr><td style="padding: 8px; color: #6b7280;">CDN URL</td><td style="padding: 8px; word-break: break-all; font-size: 12px;">${data.cdnUrl}</td></tr>
  </table>
</body>
</html>`;

return [{
  json: {
    ...data,
    token,
    sentAt: sentAt.toISOString(),
    expiresAt: expiresAt.toISOString(),
    expiresAtHuman: formatDate(expiresAt),
    waitMs,
    linkStatus: 'active',
    previewEmailHtml,
    expiryClientHtml,
    agencySummaryHtml
  }
}];
